import { Users, Activity, Calendar, DollarSign } from "lucide-react";
import { Progress } from "../components/ui/progress";

const kpiData = [
  {
    title: "Today's Total Check-ins",
    value: "142",
    icon: Activity,
    change: "+12%",
  },
  {
    title: "Active Members Count",
    value: "1,247",
    icon: Users,
    change: "+5.2%",
  },
  {
    title: "Classes Scheduled Today",
    value: "18",
    icon: Calendar,
    change: "+2",
  },
  {
    title: "Revenue MTD",
    value: "$48,392",
    icon: DollarSign,
    change: "+18.7%",
  },
];

const todaysClasses = [
  {
    time: "06:00 AM",
    name: "Morning Yoga",
    trainer: "Sarah Johnson",
    booked: 18,
    capacity: 20,
  },
  {
    time: "07:30 AM",
    name: "HIIT Training",
    trainer: "Mike Chen",
    booked: 15,
    capacity: 15,
  },
  {
    time: "09:00 AM",
    name: "Spin Class",
    trainer: "Emma Davis",
    booked: 22,
    capacity: 25,
  },
  {
    time: "11:00 AM",
    name: "CrossFit",
    trainer: "Alex Rodriguez",
    booked: 12,
    capacity: 18,
  },
  {
    time: "05:30 PM",
    name: "Boxing Fundamentals",
    trainer: "James Wilson",
    booked: 14,
    capacity: 16,
  },
  {
    time: "06:30 PM",
    name: "Power Lifting",
    trainer: "Tom Anderson",
    booked: 10,
    capacity: 12,
  },
  {
    time: "07:30 PM",
    name: "Zumba Dance",
    trainer: "Maria Garcia",
    booked: 20,
    capacity: 20,
  },
];

const recentRegistrations = [
  {
    name: "Ashley Martinez",
    date: "2 hours ago",
    plan: "Premium Annual",
    avatar: "AM",
  },
  {
    name: "David Kim",
    date: "4 hours ago",
    plan: "Standard Monthly",
    avatar: "DK",
  },
  {
    name: "Rachel Green",
    date: "6 hours ago",
    plan: "Premium Monthly",
    avatar: "RG",
  },
  {
    name: "Michael Brown",
    date: "8 hours ago",
    plan: "Standard Annual",
    avatar: "MB",
  },
  {
    name: "Jessica Lee",
    date: "12 hours ago",
    plan: "Premium Monthly",
    avatar: "JL",
  },
];

export function DashboardOverview() {
  return (
    <div className="space-y-6">
      {/* Page Title */}
      <div>
        <h1 className="text-2xl font-bold text-white">Dashboard Overview</h1>
        <p className="text-gray-400 mt-1">Welcome back! Here's what's happening today.</p>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {kpiData.map((kpi) => {
          const Icon = kpi.icon;
          return (
            <div
              key={kpi.title}
              className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl p-6 hover:border-[#39FF14]/30 transition-colors"
            >
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <p className="text-gray-400 text-sm">{kpi.title}</p>
                  <p className="text-3xl font-bold text-white mt-2">{kpi.value}</p>
                  <p className="text-[#39FF14] text-sm mt-2">{kpi.change} from yesterday</p>
                </div>
                <div className="w-12 h-12 bg-[#39FF14]/10 rounded-lg flex items-center justify-center">
                  <Icon className="w-6 h-6 text-[#39FF14]" />
                </div>
              </div>
            </div>
          );
        })}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Today's Class Schedule */}
        <div className="lg:col-span-2 bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl p-6">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-xl font-bold text-white">Today's Class Schedule</h2>
            <span className="text-sm text-gray-400">{todaysClasses.length} classes</span>
          </div>

          <div className="space-y-4">
            {todaysClasses.map((classItem, index) => {
              const percentage = (classItem.booked / classItem.capacity) * 100;
              const isFullyBooked = classItem.booked >= classItem.capacity;

              return (
                <div
                  key={index}
                  className="flex items-center gap-4 p-4 bg-[#121212] rounded-lg border border-[#2a2a2a] hover:border-[#39FF14]/20 transition-colors"
                >
                  <div className="w-20 text-center">
                    <div className="text-[#39FF14] font-bold">{classItem.time}</div>
                  </div>

                  <div className="flex-1">
                    <div className="flex items-center justify-between mb-2">
                      <div>
                        <h3 className="font-bold text-white">{classItem.name}</h3>
                        <p className="text-sm text-gray-400">{classItem.trainer}</p>
                      </div>
                      <div className="text-right">
                        <span className={`text-sm font-bold ${isFullyBooked ? 'text-[#39FF14]' : 'text-white'}`}>
                          {classItem.booked}/{classItem.capacity}
                        </span>
                        <p className="text-xs text-gray-400">booked</p>
                      </div>
                    </div>

                    <div className="w-full bg-[#2a2a2a] rounded-full h-2 overflow-hidden">
                      <div
                        className={`h-full transition-all ${
                          isFullyBooked ? 'bg-[#39FF14]' : 'bg-[#39FF14]/60'
                        }`}
                        style={{ width: `${percentage}%` }}
                      />
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Recent Member Registrations */}
        <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl p-6">
          <h2 className="text-xl font-bold text-white mb-6">Recent Member Registrations</h2>

          <div className="space-y-4">
            {recentRegistrations.map((member, index) => (
              <div
                key={index}
                className="flex items-center gap-3 p-3 bg-[#121212] rounded-lg border border-[#2a2a2a] hover:border-[#39FF14]/20 transition-colors"
              >
                <div className="w-10 h-10 rounded-full bg-[#39FF14]/20 flex items-center justify-center border border-[#39FF14]/30">
                  <span className="text-sm font-bold text-[#39FF14]">{member.avatar}</span>
                </div>
                <div className="flex-1">
                  <h4 className="font-bold text-white text-sm">{member.name}</h4>
                  <p className="text-xs text-gray-400">{member.plan}</p>
                </div>
                <div className="text-xs text-gray-500">{member.date}</div>
              </div>
            ))}
          </div>

          <button className="w-full mt-4 py-3 bg-[#121212] border border-[#2a2a2a] rounded-lg text-sm text-gray-400 hover:border-[#39FF14]/30 hover:text-white transition-colors">
            View All Members
          </button>
        </div>
      </div>
    </div>
  );
}
